object ResultUDF extends Serializable {

import org.apache.spark.sql.{DataFrame,Dataset}
import scala.collection.mutable.ArrayBuffer
import java.math.BigDecimal
import org.apache.spark.sql.types.DecimalType
import spark.implicits._

//case class s12IQu(scalarProduct:String,degreeSum:String,resultDivisor:String,rangeVal:String)
//case class s12IRe(rangeVal:String,result:String)

def extendResult(qQuerry:s12IQu): s12IRe = {
  val scalar = new BigDecimal(qQuerry.scalarProduct)
  val degree = qQuerry.degreeSum.toInt
  val divisor = new BigDecimal(qQuerry.resultDivisor)
//  val index = new BigDecimal(qQuerry.maxIndex)
  val index = new BigDecimal(qQuerry.rangeVal)
  val indexPower = index.pow(degree)
  val scalarDiv = scalar.divide(divisor)
  val result = indexPower.multiply(scalarDiv)
  val s=  s12IRe(index.toPlainString,result.toPlainString)
  println(result+"\n")
  s
}

def main(args:Array[String]) {

val df= z.get("s12OQDF").asInstanceOf[DataFrame]   //  very strange error if asInstanceOf[Dataset[]
val dfCount=df.count()
df.show(dfCount.toInt,false)    
spark.udf.register("eResult", extendResult _)

val ds: Dataset[s12IQu] = df.as[s12IQu]
val dsCount=ds.count()
ds.show(dsCount.toInt,false)
val dss=ds.map{f => extendResult(s12IQu(f.scalarProduct,f.degreeSum,f.resultDivisor,f.rangeVal)) }
val dssCount=ds.count()
dss.show(dsCount.toInt,false)

z.put("extendResultDS",dss)
}
}

object QuerryS12Initial {

import zadscripts.DFScripts
import scala.collection.mutable.ArrayBuffer
import scala.math.BigDecimal
import org.apache.spark.sql.types.DecimalType

val s3 = new DFScripts 

def s12InitialQuery(rLow:String,rHigh:String,nMax:String,d1:String,tC:String):ArrayBuffer[s12IQu] = {

val terms = new ArrayBuffer[s12IQu]()

val s12RS = s3.s12Initial(rLow,rHigh,nMax,d1,d1,d1,tC)  
while (s12RS.next()) {
terms += s12IQu(s12RS.getString(1),s12RS.getString(2),s12RS.getString(3),s12RS.getString(4),s12RS.getString(5),s12RS.getString(6),s12RS.getString(7),s12RS.getString(8),s12RS.getString(9),s12RS.getString(10),s12RS.getString(11),s12RS.getString(12),s12RS.getString(13),s12RS.getString(14),s12RS.getString(15),"4")
}
terms
}

def main(args:Array[String]) {

val terms = new ArrayBuffer[ArrayBuffer[s12IQu]]()
val nMax = "8"                                 
for(a <- 1 to 1; n <- 5 to 5;b <- 1 to (n-2)) {
     terms += s12InitialQuery(n.toString,n.toString,nMax,BigDecimal(2).pow(a).toString(),BigDecimal(2).pow(b).toString)
}

val mainTermss=terms.flatMap(_.toList)

val df = spark.createDataFrame(mainTermss)
val dfCount = df.count()
df.show(dfCount.toInt,false)
z.put("s12DF",df)
}
}

